function maxCapturedForts(forts) {
    const n = forts.length;
    let maxCapture = 0;
    for(let i = 0; i < n; i++) {
        if(forts[i] === 1) {
            for(let j = i + 1; j < n; j++) {
                if(forts[j] !== -1) {
                    let capture = 0;
                    for(let k = i + 1; k < j; k++) {
                        if(forts[k] === 0) capture++;
                    }
                    if(forts[j] === 1) maxCapture = Math.max(maxCapture, capture);
                }
            }
        }
    }
    return maxCapture;
}
